from collections import defaultdict

class LockingTree:

    def __init__(self, parent):
        self.parent = parent
        self.children = defaultdict(set)
        self.locks = [-1] * len(parent)
        for i in range(1, len(parent)):
            self.children[parent[i]].add(i)

    def lock(self, num, user):
        if self.locks[num] == -1:
            self.locks[num] = user
            return True
        return False

    def unlock(self, num, user):
        if self.locks[num] == user:
            self.locks[num] = -1
            return True
        return False

    def upgrade(self, num, user):
        if self.locks[num] != -1: return False

        cur = num
        while cur != -1:
            if self.locks[cur] != -1: return False
            cur = self.parent[cur]

        locked_descendant = self._has_locked_descendants(num)
        if locked_descendant:
            self.locks[num] = user
        return locked_descendant

    def _has_locked_descendants(self, node):
        locked_descendant = False
        for child in self.children[node]:
            if self.locks[child] != -1:
                locked_descendant = True
                self.locks[child] = -1
            locked_descendant |= self._has_locked_descendants(child)
        return locked_descendant
```


    The algorithm is the same for all languages. For each node, we store the parent and the children, and an array to keep track of the locks:

- In the `lock` function, we check if the node is not locked. If it is not locked, we lock it with the user and return true. Otherwise, return false.
- In the `unlock` function, we check if the node is locked by the user. If so, we unlock it and return true. Otherwise, return false.
- In the `upgrade` function, we first check if the node is locked; if so, return false. Then, we check if the node itself or any of its ancestors have locks; if so, return false. Finally, we check if any descendant of the node has a lock (using a recursive function); if so, we unlock the descendants, lock the node, and return true. If no descendant is locked, return false.

